// Helper to get permanent port for any repo
export function getRepoPort(repoIdOrName: string): number | undefined {
  return PORT_REGISTRY[repoIdOrName];
}

// Helper to get external URL for any repo
export function getRepoUrl(repoIdOrName: string): string | undefined {
  const port = getRepoPort(repoIdOrName);
  return port ? url(port) : undefined;
}
